# Validation helper
def validate_record(record: dict) -> list[str]:
    errors = []
    errors.extend(
        pick_validation_errors(
            record,
            required_keys=["id", "name", "email", "team", "score"],
            expected_types={
                "id": int,
                "name": (str, type(None)),
                "email": str,
                "score": (int, float, str),
            },
        )
    )

    if not is_non_empty_string(record.get("name")):
        errors.append("name must be non-empty")
    if not is_valid_email(record.get("email", "")):
        errors.append("email must be valid")
    if isinstance(record.get("score"), (int, float)) and not in_numeric_range(record["score"], 0, 100):
        errors.append("score must be in range 0..100")

    return errors

validation_results = [
    {"id": r.get("id"), "errors": validate_record(r)} for r in records
]
validation_results
